import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.6ZJjlmu_.js";const i="/apps/public/eventmonitor/images/package-manager-samples-import.png",m=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md"}'),s={name:"guide/installation.md"};function r(l,e,c,p,d,h){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="unity-version" tabindex="-1">Unity version <a class="header-anchor" href="#unity-version" aria-label="Permalink to &quot;Unity version&quot;">​</a></h2><p>Event Monitor is built and tested with <strong>Unity 6 LTS</strong> (for example <code>6000.3.7f1</code>). The package relies on Unity’s <strong>IL Post-Processor</strong> pipeline, which is available in modern Unity versions. If you use an older editor, verify ILPP support before relying on automatic instrumentation.</p><h2 id="compatibility-matrix-tested" tabindex="-1">Compatibility matrix (tested) <a class="header-anchor" href="#compatibility-matrix-tested" aria-label="Permalink to &quot;Compatibility matrix (tested)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Unity version</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>6000.3.7f1</code></td><td>Supported</td><td>Primary target (Unity 6 LTS)</td></tr><tr><td><code>2022.3.62f3</code></td><td>Supported</td><td>Verified by import and runtime test</td></tr></tbody></table><h2 id="install-via-upm-copy-paste" tabindex="-1">Install via UPM (copy-paste) <a class="header-anchor" href="#install-via-upm-copy-paste" aria-label="Permalink to &quot;Install via UPM (copy-paste)&quot;">​</a></h2><p>Recommended path is Unity Package Manager.</p><h3 id="option-a-package-manager-ui" tabindex="-1">Option A: Package Manager UI <a class="header-anchor" href="#option-a-package-manager-ui" aria-label="Permalink to &quot;Option A: Package Manager UI&quot;">​</a></h3><ol><li>Open <strong>Window -&gt; Package Manager</strong></li><li>Click <strong>+</strong></li><li>Choose <strong>Add package from git URL...</strong></li><li>Paste your Event Monitor repository URL</li></ol><h3 id="option-b-manifest-json" tabindex="-1">Option B: <code>manifest.json</code> <a class="header-anchor" href="#option-b-manifest-json" aria-label="Permalink to &quot;Option B: \`manifest.json\`&quot;">​</a></h3><p>Add the package to <code>Packages/manifest.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dependencies&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;com.pawelca.eventmonitor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/your-org/eventmonitor.git&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Replace only the repository URL with your actual source.</p><p>When installed this way, Event Monitor can declare and restore its own dependencies automatically (including Mono.Cecil).</p><h2 id="package-layout" tabindex="-1">Package layout <a class="header-anchor" href="#package-layout" aria-label="Permalink to &quot;Package layout&quot;">​</a></h2><p>After install, the package typically contains:</p><ul><li><strong>Runtime</strong> — <code>EventBus</code>, <code>EventRecord</code>, optional <code>ReflectionScanner</code>.</li><li><strong>Editor</strong> — <code>EventMonitor</code> window, settings, demo scene tooling.</li><li><strong>IL Post-Processors</strong> — assembly that rewrites user assemblies at compile time.</li></ul><p>Exact folder names may vary by version; treat this documentation as product-level guidance.</p><h2 id="dependency-mono-cecil-automatic-in-upm-flow" tabindex="-1">Dependency: Mono.Cecil (automatic in UPM flow) <a class="header-anchor" href="#dependency-mono-cecil-automatic-in-upm-flow" aria-label="Permalink to &quot;Dependency: Mono.Cecil (automatic in UPM flow)&quot;">​</a></h2><p>The IL post-processor depends on <strong>Mono.Cecil</strong>:</p><ul><li><code>com.unity.nuget.mono-cecil</code> (for example <code>1.11.6</code>)</li></ul><p>For UPM package installation, this dependency should be resolved automatically by <code>package.json</code>. If you use legacy asset export/import, see <a href="./import-checklist.html">Import checklist</a>.</p><h2 id="which-assemblies-get-instrumented" tabindex="-1">Which assemblies get instrumented? <a class="header-anchor" href="#which-assemblies-get-instrumented" aria-label="Permalink to &quot;Which assemblies get instrumented?&quot;">​</a></h2><p>The post-processor <strong>does not</strong> rewrite every DLL in your project. Typical <strong>user</strong> script assemblies (for example <code>Assembly-CSharp</code> and many custom <strong>asmdef</strong> assemblies) are candidates. <strong>Unity engine</strong>, <strong>Editor</strong>, <strong>system</strong>, and <strong>Event Monitor’s own</strong> assemblies are skipped to avoid recursion and noise.</p><p>If your gameplay code lives in a <strong>custom asmdef</strong>, that assembly is usually still processed as long as it is allow-listed by the tool’s gate and recording is enabled. See <a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics and settings</a> and <a href="./../reference/il-limitations.html">IL patterns and limitations</a>.</p><h2 id="verify-instrumentation" tabindex="-1">Verify instrumentation <a class="header-anchor" href="#verify-instrumentation" aria-label="Permalink to &quot;Verify instrumentation&quot;">​</a></h2><p>After installation:</p><ol><li>Open <strong>Window → Event Monitor</strong> and enable <strong>Record</strong>.</li><li>Enter <strong>Play Mode</strong> and trigger a known <code>event +=</code> / <code>?.Invoke()</code> path.</li><li>Confirm <strong>SUB</strong> / <strong>INVOKE</strong> rows appear.</li></ol><p>If nothing appears, use <a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a> and optional ILPP diagnostics.</p><h2 id="import-demo-scene-sample-package-manager" tabindex="-1">Import Demo Scene sample (Package Manager) <a class="header-anchor" href="#import-demo-scene-sample-package-manager" aria-label="Permalink to &quot;Import Demo Scene sample (Package Manager)&quot;">​</a></h2><p>To enable <code>Tools/Event Monitor/Generate Demo Scene</code>:</p><ol><li>Open <strong>Window -&gt; Package Manager</strong></li><li>Select <strong>Event Monitor</strong></li><li>Open the <strong>Samples</strong> tab</li><li>Click <strong>Import</strong> on <strong>Demo Scene Generator</strong></li></ol><p><img src="`+i+'" alt="Package Manager Samples import flow"></p><h2 id="next-step" tabindex="-1">Next step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next step&quot;">​</a></h2><p>Continue with <a href="./quick-start.html">Quick Start</a>.</p><p>If you imported Event Monitor via asset export into another project, use <a href="./import-checklist.html">Import checklist</a>.</p>',36)])])}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
